Event GridMotoristas.Load
&RankingMot = 0 //Ranking
//Paginação &GridMotoristasPageCount = 1 &GridMotoristasLinhaPorPage = GridMotoristas.Rows &GridMotoristasPagina = 0
//Carrega com base na quantidade de viagens realizadas For Each Order (PesQtdVia), EmpCod, PesCod Where EmpCod = &Context.EmpCod //Empresa Where PesIsMot = True //Motorista Where PesSts = Status_AtivoInativo.ATIVO //Ativo Where PesQtdVia > 0 //Mais de uma viagem
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
//this code should be inside the For Each used to load the grid
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
&RankingMot += 1 //Ranking &PesNom = PesRaz //Razão Social &QtdViagens = PesQtdVia //Quantidade de Viagens realizadas
//Paginação &GridMotoristasPagina += 1 If &GridMotoristasPagina = &GridMotoristasLinhaPorPage &GridMotoristasPageCount += 1 &GridMotoristasPagina = 0 EndIF
Load EndFor
EndEvent
Event GridVeiculos.Load
&RankingVei = 0 //Ranking
//Paginação &GridVeiculosPageCount = 1 &GridVeiculosLinhaPorPage = GridVeiculos.Rows &GridVeiculosPagina = 0
//Carrega com base no KM rodado For Each Order (VeiUltKm), EmpCod, VeiCod Where EmpCod = &Context.EmpCod //Empresa Where VeiUltKm > 0 //Km acima de 0
&RankingVei += 1 //Ranking
&VeiPla = VeiPla //Placa &VeiKm = VeiUltKm //Quilometragem
