//Paginação &GridVeiculosPagina += 1 If &GridVeiculosPagina = &GridVeiculosLinhaPorPage &GridVeiculosPageCount += 1 &GridVeiculosPagina = 0 EndIf
Load EndFor
EndEvent
Event GridMotoristasPaginationBar.ChangePage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case GridMotoristasPaginationBar.SelectedPage = !'Previous' &GridMotoristasCurrentPage -= 1 GridMotoristas.PreviousPage() Case GridMotoristasPaginationBar.SelectedPage = !'Next' &GridMotoristasCurrentPage += 1 GridMotoristas.NextPage() Otherwise &PageToGo.FromString(GridMotoristasPaginationBar.SelectedPage) &GridMotoristasCurrentPage = &PageToGo GridMotoristas.GotoPage(&PageToGo) EndCase Refresh
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event GridMotoristasPaginationBar.ChangeRowsPerPage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
GridMotoristas.Rows = GridMotoristasPaginationBar.RowsPerPageSelectedValue &GridMotoristasCurrentPage = 1 GridMotoristas.FirstPage()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
