Sub 'CarregaDados'
&Atualizado = ServerNow() //Horário
//Retorna dados dos Cards prcDadosDashBoardFrotas.Call(&Context.EmpCod, &Context.FilCod, &FrotaQtd, &MotoristasQtd, &CNHAtraso, &ViaQtd, &MotoristaTransito, &VeiculosTransito, &Viagens_ProgressValue, &MotoristasTransito_ProgressValue, &VeiculosTransito_ProgressValue, &CNHAtraso_ProgressValue)
//Informações adicionais &Frota_AdditionalData = 'Atualizado em: ' + Trim(ToFormattedString(&Atualizado)) &Motoristas_AdditionalData = 'Atualizado em: ' + Trim(ToFormattedString(&Atualizado)) &Viagens_AdditionalData = 'Atualizado em: ' + Trim(ToFormattedString(&Atualizado)) &MotoristasTransito_AdditionalData = Trim(ToFormattedString(&MotoristasTransito_ProgressValue)) + ' do total cadastrado' &VeiculosTransito_AdditionalData = Trim(ToFormattedString(&VeiculosTransito_ProgressValue)) + ' da Frota atual' &CNHAtraso_AdditionalData = 'Dentro de 30 dias'
//Progresso da barra Viagens_Progress.Percentage = &Viagens_ProgressValue MotoristasTransito_Progress.Percentage = &MotoristasTransito_ProgressValue VeiculosTransito_Progress.Percentage = &VeiculosTransito_ProgressValue CNHAtraso_Progress.Percentage = &CNHAtraso_ProgressValue
EndSub
